# Single-letter shorthand
BASE_COLORS = {
    'b': (0.0, 0.0, 1.0), 'g': (0.0, 0.5, 0.0), 'r': (1.0, 0.0, 0.0),
    'c': (0.0, 0.75, 0.75), 'm': (0.75, 0.0, 0.75), 'y': (0.75, 0.75, 0.0),
    'k': (0.0, 0.0, 0.0), 'w': (1.0, 1.0, 1.0),
}

